import (
    "context"
    "errors"
    "fmt"
    "time"

    "github.com/hashicorp/boundary/internal/servers/controller/common"
)

// sessionConnectionCleanupJob defines a periodic job that monitors workers for loss of connection and terminates connections on workers that have not sent a heartbeat in a significant period of time.
// Relevant connections are simply marked as disconnected in the database. Connections will be independently terminated by the worker, or the event of a synchronization issue between the two, the controller will win out and order that the connections be closed on the worker.
type sessionConnectionCleanupJob struct {
    connectionRepoFn common.ConnectionRepoFactory

    // The amount of time to give disconnected workers before marking
    // their connections as closed.
    gracePeriod time.Duration

    // The total number of connections closed in the last run.
    totalClosed int
}

func newSessionConnectionCleanupJob(
    connectionRepoFn common.ConnectionRepoFactory,
    gracePeriod time.Duration,
) (*sessionConnectionCleanupJob, error) {
    const op = "controller.newNewSessionConnectionCleanupJob"
    switch {
    case connectionRepoFn == nil:
        return nil, errors.NewDeprecated(errors.InvalidParameter, op, "missing connectionRepoFn")
    case gracePeriod < session.DeadWorkerConnCloseMinGrace:
        return nil, errors.NewDeprecated(
            errors.InvalidParameter, op,
            fmt.Sprintf("invalid gracePeriod, must be greater than %s", session.DeadWorkerConnCloseMinGrace))
    }

    return &sessionConnectionCleanupJob{
        connectionRepoFn: connectionRepoFn,
        gracePeriod:      gracePeriod,
    }, nil
}

// Name implements scheduler.Job.
func (j *sessionConnectionCleanupJob) Name() string {
    return "sessionConnectionCleanupJob"
}

// Description implements scheduler.Job.
func (j *sessionConnectionCleanupJob) Description() string {
    return "Closes connections on dead workers"
}

// Status implements scheduler.Job.
func (j *sessionConnectionCleanupJob) Status() scheduler.JobStatus {
    return scheduler.JobStatus{Completed: j.totalClosed, Total: j.totalClosed}
}

// Run performs the cleanup of stale worker connections.
func (j *sessionConnectionCleanupJob) Run(ctx context.Context) error {
    repo, err := j.connectionRepoFn()
    if err != nil {
        return err
    }
    results, err := repo.CloseConnectionsForDeadWorkers(ctx, j.gracePeriod)
    if err != nil {
        return err
    }
    j.totalClosed = 0
    for range results {
        j.totalClosed++
    }
    return nil
}

// NextRunIn implements scheduler.Job.
func (j *sessionConnectionCleanupJob) NextRunIn(ctx context.Context) (time.Duration, error) {
    return 0, nil
}

